5	  // Empty / processing fee
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
8	    expect(quote(customer, [])).toBe(5);
9	  });
10	
11	  // Base premiums for single items (with first insurance + fee, newcomer)
12	  it.todo("quote for a single plain sword (newcomer, no contracts) yields 115 G (100 base + 10 first + 5 fee)");
