16	
17	  // Components base premiums
18	  it.todo("quote for 2 runes yields base premium 50 G (no block applies)");
19	  it.todo("quote for 3 runes yields base premium 60 G (block of 3 alike applies)");
20	  it.todo("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)");
21	  it.todo("quote for 7 runes yields base premium 175 G (one block of 3 + 4 individual)");
