55	  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");
56	
57	  // Claim payout rounding
58	  it.todo("payout of 350.5 G is rounded DOWN to 350 G");
59	
60	  // Deductible per damage event
61	  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");
62	
63	  // Special reimbursement clauses
64	  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
65	  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
66	  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
67	  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");
68	
69	  // Cap
70	  it.todo("sword policy (sum 1000, cap 2000): two claims of 1500 each yield first payout 1400 G with cap 600 remaining");
71	  it.todo("sword policy second claim of 1500 G with 600 G cap remaining yields payout 600 G and cap 0");
72	  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
73	  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount affects only premium, not insurance sum)");
74	
75	  // Multiple items of same type
76	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
77	  it.todo("two sword damage entries each get their own deductible when both swords are insured");
78	  it.todo("two sword damage entries when only one sword is insured: claim is rejected");
